mapper.select:
SELECT id, username, password, nickname, role, created_at, updated_at
FROM members
WHERE id = #{id}

SELECT id, username, password, nickname, role, created_at, updated_at
FROM members
WHERE username = #{username}

SELECT id, username, password, nickname, role, created_at, updated_at
FROM members
WHERE nickname = #{nickname}

SELECT EXISTS(
    SELECT 1
    FROM members
    WHERE username = #{username}
)

SELECT EXISTS(
    SELECT 1
    FROM members
    WHERE nickname = #{nickname}
)
